    gnd_chk.m_pos.z = pPos[0].z;

    f32 groundY = 1.5f + bg->GroundCross(&gnd_chk);
    if (groundY - pPos[0].y > 50.0f) {
        groundY = pPos[0].y;
    }

    dampOffset.x = 0.0f;
    dampOffset.y = 0.0f;
    dampOffset.z = 0.0f;
    waveOffset.x = 0.0f;
    waveOffset.y = 0.0f;
    waveOffset.z = 0.0f;
    waveResult.x = 0.0f;
    waveResult.y = 0.0f;
