/* 000017EC-000019C0       .text mant_move__FP10mant_class */
void mant_move(mant_class* i_this) {
    v_count = 0;
    v_pos = (cXyz*)(&((cXyz*)((u8*)i_this + 0x310))[i_this->mPacket.mTexNo * 81]);
    mesh_cc_ct = 0;

    mant_v_calc(i_this);
    mant_n_calc(i_this);
    {
        u8* base = (u8*)i_this;
        base += i_this->mPacket.mTexNo * 0x3CC;
        DCStoreRangeNoSync((void*)(base + 0x310), 0x3CC);
    }

    if (i_this->field_0x2838 != 0) {
        i_this->field_0x2838--;
        {
            u8* base = (u8*)i_this;
            base += i_this->mPacket.mTexNo * 0x3CC;
            cXyz* pPos = (cXyz*)(base + 0x310);
            int i;
            for (i = 0; i < 0x51; i++) {
                if ((i & 3) == 0) {
                    g_dComIfG_gameInfo.play.mParticle->setSimple(0x8069, pPos, 0xFF, g_whiteColor, g_whiteColor, 0);
                }
                pPos++;
            }
            if (i_this->field_0x2838 <= 2) {
                fopAcM_delete(i_this);
                return;
            }
        }
    }

    cLib_addCalc2(&i_this->mWindStr, 30.0f, 0.1f, 1.0f);
    cLib_addCalc2(&i_this->mDamping, 0.7f, 0.1f, 0.05f);

    if (i_this->mWindSph.ChkTgHit()) {
        i_this->m1C0E = 10;
        i_this->m1C0C = dComIfGp_getPlayer(0)->shape_angle.y;
    }

    if (i_this->m1C0E != 0) {
        i_this->m1C0E--;
        cLib_addCalc2(&i_this->m1C00, 50.0f, 0.2f, 1.5f);
    } else {
        cLib_addCalc0(&i_this->m1C00, 0.1f, 1.0f);
    }

    if (i_this->m1C0E > 4) {
        cLib_addCalc2(&i_this->m1C04, 1.0f, 1.0f, 1.0f);
    } else {
        cLib_addCalc0(&i_this->m1C04, 0.1f, 0.1f);
    }
}

